async (page) => {
  // Click on the fire-test label to see if it shows output
  const rows = await page.getByRole('row').all();
  for (const row of rows) {
    const text = await row.textContent();
    if (text && text.includes('fire-test')) {
      await row.click();
      await page.waitForTimeout(500);
      const snapshot = await page.content();
      // Check for any modal or expanded content
      return text + '||' + (await page.locator('[data-testid="action-result"], .action-result, pre').textContent().catch(() => 'no result panel'));
    }
  }
  return 'row not found';
}

