  // Check if completed badge has hover or title
  const completedBadge = page.locator('text=Completed').first();
  await completedBadge.hover();
  await page.waitForTimeout(300);
  // Check for tooltip
  const tooltips = await page.locator('[role="tooltip"], [data-tooltip], [title]').all();
  const tooltipTexts = await Promise.all(tooltips.map(t => t.textContent()));
  return JSON.stringify({ tooltips: tooltipTexts });
}

